#include <bits/stdc++.h>
using namespace std;
const int N=1000005;
int n,q,a[N],fa[N][20],dep[N],cnt;
vector<int> g[N];
void dfs(int u,int f)
{
	fa[u][0]=f;
	dep[u]=dep[f]+1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs(v,u);
	}
}
int lca(int x,int y)
{
	if(dep[y]<dep[x]) swap(x,y);
	int k=log2(dep[y])+1;
	for(int i=k;i>=0;i--)
	{
		if((dep[y]-(1<<i))>=dep[x]) y=fa[y][i];
	}
	if(x==y) return x;
	for(int i=k;i>=0;i--)
	{
		if(fa[x][i]&&fa[x][i]!=fa[y][i])
		{
			x=fa[x][i];
			y=fa[y][i];
		}
	}
	return fa[x][0];
}
void dfs2(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f) continue;
		dfs2(v,u);
		a[u]+=a[v];
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>q;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	dfs(1,0);
	for(int j=1;(1<<j)<=n;j++)
	{
		for(int i=1;i<=n;i++)
		{
			fa[i][j]=fa[fa[i][j-1]][j-1];
		}
	}
	while(q--)
	{
		int u,v;
		cin>>u>>v;
		int tmp=lca(u,v);
		a[u]++;
		a[v]++;
		a[tmp]--;
		a[fa[tmp][0]]--;
	}
	dfs2(1,0);
	int u,v;
	cin>>u>>v;
	int tmp=lca(u,v);
	while(u!=tmp)
	{
		if(a[u]==0) cnt++;
		u=fa[u][0];
	}
	while(v!=tmp)
	{
		if(a[v]==0) cnt++;
		v=fa[v][0];
	}
	if(a[u]==0) cnt++;
	cout<<cnt;
	return 0;
}
